// Canonical seed dataset for VO2 Builder.
//
// This is the single source of truth for the 8 mockup sessions. It is consumed
// by BOTH `supabase/seed.ts` (to populate a real database) and `lib/data.ts`
// (as the in-memory fallback when Supabase env vars are absent, so the app is
// demoable out of the box). HR streams are generated by a deterministic PRNG so
// the dataset is byte-stable across runs and reloads.

import type {
  AppSettings,
  HRSamplePoint,
  HRStream,
  Session,
  SessionModalityDetail,
  VO2BuilderEvent,
} from "./types";

const NOW = "2026-07-10T09:32:00.000Z";

// --- deterministic PRNG (mulberry32) --------------------------------------
function mulberry32(seed: number) {
  return function () {
    seed |= 0;
    seed = (seed + 0x6d2b79f5) | 0;
    let t = Math.imul(seed ^ (seed >>> 15), 1 | seed);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

/**
 * Generate a synthetic second-by-second-ish HR stream, sampled every `step`
 * seconds, shaped by session type:
 *   - zone2:     starts ~115, gradual upward drift to ~130, mild noise
 *   - intervals: 4×4 structure — ~110 recovery / 165–185 effort blocks
 *   - benchmark: steady build from ~140 to ~175
 */
export function generateHRStream(
  sessionType: Session["session_type"],
  durationSeconds: number,
  seed: number,
  step = 5
): HRSamplePoint[] {
  const rand = mulberry32(seed);
  const points: HRSamplePoint[] = [];
  const n = Math.floor(durationSeconds / step);

  if (sessionType === "intervals") {
    // 4 work intervals of 4 min with recovery between; warm-up + cool-down.
    const workBpm = () => 168 + rand() * 17; // 168–185
    const recBpm = () => 105 + rand() * 12; // 105–117
    for (let i = 0; i <= n; i++) {
      const t = i * step;
      const mins = t / 60;
      let base: number;
      if (mins < 4)
        base = 100 + (mins / 4) * 55; // warm-up ramp
      else {
        const cyclePos = (mins - 4) % 6; // 4 min work + 2 min rest
        base = cyclePos < 4 ? workBpm() : recBpm();
      }
      const noise = (rand() - 0.5) * 4;
      points.push({ time: t, heartrate: Math.round(base + noise) });
    }
  } else if (sessionType === "benchmark") {
    for (let i = 0; i <= n; i++) {
      const t = i * step;
      const frac = i / n;
      const base = 140 + frac * 35; // 140 -> 175
      const noise = (rand() - 0.5) * 5;
      points.push({ time: t, heartrate: Math.round(base + noise) });
    }
  } else {
    // zone2
    for (let i = 0; i <= n; i++) {
      const t = i * step;
      const frac = i / n;
      const base = 115 + frac * 15; // 115 -> 130 drift
      const noise = (rand() - 0.5) * 6;
      points.push({ time: t, heartrate: Math.round(base + noise) });
    }
  }
  return points;
}

// --- ids ------------------------------------------------------------------
const id = (n: number) =>
  `00000000-0000-4000-8000-${String(n).padStart(12, "0")}`;

// --- app_settings ---------------------------------------------------------
export const SEED_SETTINGS: AppSettings = {
  id: id(900),
  max_heartrate: 192,
  updated_at: NOW,
};

