export const SEED_SESSIONS: Session[] = SPECS.map((s, i) => ({
  id: id(i + 1),
  strava_activity_id: s.stravaId,
  name: s.name,
  session_date: s.date,
  modality: s.modality,
  session_type: s.type,
  duration_seconds: s.durationSeconds,
  avg_heartrate: s.avg,
  max_heartrate: s.peak,
  notes: s.notes,
  strava_synced_at: `${s.date}T09:30:00.000Z`,
  deleted_at: null,
  created_at: `${s.date}T09:30:00.000Z`,
  updated_at: `${s.date}T09:30:00.000Z`,
}));

export const SEED_DETAILS: SessionModalityDetail[] = SPECS.map((s, i) => ({
  id: id(i + 100),
  session_id: id(i + 1),
  speed_mph: s.detail.speed_mph ?? null,
  incline_pct: s.detail.incline_pct ?? null,
  avg_split: s.detail.avg_split ?? null,
  avg_power_watts: s.detail.avg_power_watts ?? null,
  avg_cadence_rpm: s.detail.avg_cadence_rpm ?? null,
  avg_pace: s.detail.avg_pace ?? null,
  route_notes: s.detail.route_notes ?? null,
  created_at: `${s.date}T09:30:00.000Z`,
  updated_at: `${s.date}T09:30:00.000Z`,
}));

export const SEED_STREAMS: HRStream[] = SPECS.map((s, i) => {
  const data = generateHRStream(s.type, s.durationSeconds, i + 1);
  return {
    id: id(i + 200),
    session_id: id(i + 1),
    data,
    resolution: "high",
    original_size: s.durationSeconds,
    created_at: `${s.date}T09:31:00.000Z`,
  };
});

export const SEED_EVENTS: VO2BuilderEvent[] = SPECS.flatMap((s, i) => {
  const base: VO2BuilderEvent = {
    id: id(i + 300),
    session_id: id(i + 1),
    event_type: "session_created",
    payload: {
      name: s.name,
      strava_activity_id: s.stravaId,
      session_type: s.type,
    },
    created_at: `${s.date}T09:30:30.000Z`,
  };
  const streamEvent: VO2BuilderEvent = {
    id: id(i + 400),
    session_id: id(i + 1),
    event_type: "hr_stream_attached",
    payload: { data_points: s.durationSeconds, resolution: "high" },
    created_at: `${s.date}T09:31:00.000Z`,
  };
  return [base, streamEvent];
});
